const items = document.querySelectorAll('.item');
const list = [];
items.forEach((el, i) => {
  const titleEl = el.querySelector('.title a, .pl2 a');
  const ratingEl = el.querySelector('.rating_nums');
  const imgEl = el.querySelector('img');
  if (titleEl) {
    list.push({
      rank: i + 1,
      title: titleEl.textContent.trim().replace(/\\s+/g, ' '),
      rating: ratingEl ? ratingEl.textContent.trim() : '',
      url: titleEl.href || '',
      cover: imgEl ? imgEl.src : '',
    });
  }
});
return JSON.stringify(list);

var items = document.querySelectorAll('.item, ol.grid_view li');
var list = [];
items.forEach(function(el) {
  var rankEl = el.querySelector('.pic em, em');
  var titleEl = el.querySelector('.title, .hd a span:first-child');
  var ratingEl = el.querySelector('.rating_num, [class*="rating_num"]');
  var linkEl = el.querySelector('a[href*="subject"]');
  if (titleEl) {
    list.push({
      rank: rankEl ? parseInt(rankEl.textContent) : list.length + 1,
      title: titleEl.textContent.trim(),
      rating: ratingEl ? ratingEl.textContent.trim() : '',
      url: linkEl ? linkEl.href : '',
    });
  }
});
return JSON.stringify(list);

var html = document.documentElement.outerHTML;
var regex = /<a[^>]*href="\/(\d{7,})\.html"[^>]*>(?:<[^>]*>)*([^<]+)/g;
var list = [];
var match;
var seen = {};
while ((match = regex.exec(html)) !== null) {
  var tid = match[1];
  var title = match[2].trim();
  if (!title || seen[tid]) continue;
  seen[tid] = true;
  list.push({
    rank: list.length + 1,
    title: title,
    url: 'https://bbs.hupu.com/' + tid + '.html',
  });
}
return JSON.stringify(list.slice(0, 30));

var scripts = document.querySelectorAll('script[type="application/ld+json"]');
for (var s of scripts) {
  try {
    var json = JSON.parse(s.textContent);
    if (json['@type'] === 'ItemList' && json.itemListElement) {
      var list = json.itemListElement.slice(0, 25).map(function(el, i) {
        var item = el.item || el;
        return {
          rank: el.position || i + 1,
          title: item.name || '',
          rating: item.aggregateRating ? item.aggregateRating.ratingValue : '',
          genre: Array.isArray(item.genre) ? item.genre.join(', ') : (item.genre || ''),
          url: item.url ? (item.url.startsWith('http') ? item.url : 'https://www.imdb.com' + item.url) : '',
        };
      });
      return JSON.stringify(list);
    }
  } catch(e) {}
}
var rows = document.querySelectorAll('.ipc-metadata-list-summary-item, li[class*="ipc-metadata-list"]');
var fallback = [];
rows.forEach(function(row, i) {
  var titleEl = row.querySelector('h3, [class*="title"]');
  var ratingEl = row.querySelector('[class*="rating"], [aria-label*="rating"]');
  if (titleEl && i < 25) {
    fallback.push({
      rank: i + 1,
      title: titleEl.textContent.trim().replace(/^\d+\.\s*/, ''),
      rating: ratingEl ? ratingEl.textContent.trim() : '',
      url: '',
    });
  }
});
return JSON.stringify(fallback);

var items = document.querySelectorAll('#search_resultsRows a');
var list = [];
items.forEach(function(el, i) {
  var t = el.querySelector('.title');
  var p = el.querySelector('.discount_final_price, .search_price');
  if (t && list.length < 30) list.push({rank: list.length+1, name: t.textContent.trim(), url: el.href, price: p ? p.textContent.trim() : ''});
});
return JSON.stringify(list);

var items = document.querySelectorAll('ytd-video-renderer, ytd-rich-item-renderer');
var list = [];
items.forEach(function(el, i) {
  var t = el.querySelector('#video-title');
  var c = el.querySelector('#channel-name a, ytd-channel-name a');
  var v = el.querySelector('#metadata-line span');
  if (t && list.length < 30) list.push({rank: list.length+1, title: t.textContent.trim(), url: t.href || '', channel: c ? c.textContent.trim() : '', views: v ? v.textContent.trim() : ''});
});
return JSON.stringify(list);

var items = document.querySelectorAll('.chart-dashed-list li, .article .item');
var list = [];
items.forEach(function(el, i) {
  var t = el.querySelector('a.fleft, .title a, h2 a');
  var r = el.querySelector('.rating_nums, [class*="rating"]');
  if (t && list.length < 30) list.push({rank: list.length+1, title: t.textContent.trim(), url: t.href, rating: r ? r.textContent.trim() : ''});
});
return JSON.stringify(list);

var items = document.querySelectorAll('.item-root, .sc-bZQynM');
var list = [];
items.forEach(function(el, i) {
  var t = el.querySelector('.title-text, h3 a, a.title-text');
  var r = el.querySelector('.rating_nums, [class*="rating"]');
  var meta = el.querySelector('.meta, [class*="meta"]');
  if (t && list.length < 20) list.push({rank: list.length+1, title: t.textContent.trim(), url: t.href || '', rating: r ? r.textContent.trim() : '', info: meta ? meta.textContent.trim() : ''});
});
return JSON.stringify(list);

try {
  var text = document.body?.innerText || document.querySelector('pre')?.textContent || '';
  var data = JSON.parse(text);
  var results = (data?.feed?.results || []).map(function(p, i) {
    return {rank: i+1, title: p.name, author: p.artistName, id: p.id, url: p.url || ''};
  });
  return results.slice(0, 25);
} catch(e) { return [{error: 'Failed to parse podcast data'}]; }

var cards = document.querySelectorAll('[data-e2e="explore-item"], [class*="DivItemContainer"], [class*="video-feed-item"]');
var results = [];
cards.forEach(function(card, idx) {
  var a = card.querySelector('a[href*="/video/"]') || card.querySelector('a');
  var desc = card.querySelector('[data-e2e="explore-item-desc"], [class*="ItemDescription"], p')?.textContent?.trim() || '';
  var author = card.querySelector('[data-e2e="explore-item-user"], [class*="Author"], span[class*="user"]')?.textContent?.trim() || '';
  var views = card.querySelector('[class*="play"], [class*="view"]')?.textContent?.trim() || '';
  var href = a ? a.getAttribute('href') : '';
  if (href && !href.startsWith('http')) href = 'https://www.tiktok.com' + href;
  if (desc || href) results.push({rank: idx+1, description: desc.slice(0,100), author: author, views: views, url: href});
});
return results.slice(0, 20);

var items = document.querySelectorAll('.ranking-item, [class*="rankingItem"]');
var results = [];
items.forEach(function(item, idx) {
  var titleEl = item.querySelector('.title, a[data-title], h2');
  var title = titleEl ? (titleEl.getAttribute('data-title') || titleEl.textContent || '').trim() : '';
  var userEl = item.querySelector('.user-name, [data-user-name]');
  var user = userEl ? (userEl.getAttribute('data-user-name') || userEl.textContent || '').trim() : '';
  var a = item.querySelector('a[href*="/artworks/"]');
  var href = a ? a.getAttribute('href') : '';
  if (href && !href.startsWith('http')) href = 'https://www.pixiv.net' + href;
  if (title || href) results.push({rank: idx+1, title: title, author: user, url: href});
});
return results.slice(0, 30);
